const raw = $input.first().json;
const body = raw.body || raw || {};

const toBool = (value) => {
  if (typeof value === 'boolean') return value;
  const normalized = String(value ?? '').trim().toLowerCase();
  return ['true', '1', 'yes', 'si', 'sí', 'y'].includes(normalized);
};

const getCustomField = (fields, key) => {
  if (Array.isArray(fields)) {
    const hit = fields.find((item) => item?.name === key || item?.key === key || item?.field_name === key);
    return hit?.value ?? '';
  }
  if (fields && typeof fields === 'object') {
    return fields[key] ?? '';
  }
  return '';
};

const subscriberId = String(body.subscriber_id || body.id || '');
const message = String(body.message || body.last_input_text || '').trim();
const customFields = body.custom_fields || {};
const storefrontOrderMatch = message.match(/pedido\s+web\s*#?\s*(\d+)[^\n]*?\btoken\b\s*([a-z0-9_-]{8,64})/i) || message.match(/#(\d+)[^\n]*?\btoken\b\s*([a-z0-9_-]{8,64})/i);
const storefrontOrderId = storefrontOrderMatch ? Number(storefrontOrderMatch[1]) : null;
const storefrontOrderToken = storefrontOrderMatch ? String(storefrontOrderMatch[2] || '').trim().toLowerCase() : '';

return [{
  json: {
    subscriber_id: subscriberId,
    first_name: body.first_name || 'amigo',
    last_name: body.last_name || '',
    phone: body.whatsapp_phone || body.phone || '',
    timezone: body.timezone || '',
    channel: 'manychat',
    city: getCustomField(customFields, 'city'),
    funnel_stage: getCustomField(customFields, 'funnel_stage'),
    interested_product: getCustomField(customFields, 'interested_product'),
    is_human_active: toBool(getCustomField(customFields, 'is_human_active')),
    raw_message: message,
    is_audio: message.startsWith('https://') && (message.includes('fbsbx.com') || message.includes('fbcdn.net') || message.includes('manybot-files.s3')),
    is_empty: !message,
    storefront_order_id: Number.isFinite(storefrontOrderId) ? storefrontOrderId : null,
    storefront_order_token: storefrontOrderToken || '',
  }
}];

const parsed = $('Parse Input').first().json;
let userMessage = String(parsed.raw_message || '');
let wasAudio = false;

try {
  const whisper = $('Groq Whisper Transcribe').first().json;
  if (whisper && typeof whisper === 'object' && whisper.text) {
    userMessage = String(whisper.text).trim();
    wasAudio = true;
  }
} catch (error) {
  wasAudio = false;
}

return [{
  json: {
    ...parsed,
    user_message: userMessage.trim() || '(vacío)',
    was_audio: wasAudio,
  }
}];

const base = $('Merge Input').first().json || {};
const raw = $input.first().json;

const pickId = (value) => {
  if (value == null || value === '') return null;
  const num = Number(value);
  return Number.isFinite(num) && num > 0 ? num : null;
};

const candidates = [];

if (Array.isArray(raw)) {
  candidates.push(...raw);
}

if (raw && typeof raw === 'object') {
  candidates.push(raw);

  for (const key of ['body', 'data', 'result']) {
    const nested = raw[key];
    if (Array.isArray(nested)) {
      candidates.push(...nested);
    } else if (nested && typeof nested === 'object') {
      candidates.push(nested);
    }
  }
}

let customerId = null;

for (const candidate of candidates) {
  if (!candidate || typeof candidate !== 'object') continue;
  customerId = pickId(candidate.upsert_customer ?? candidate.customer_id ?? candidate.id);
  if (customerId != null) break;
}

return [{
  json: {
    ...base,
    customer_id: customerId,
  }
}];

const base = $('Attach Customer Id').first().json || {};
const raw = $input.first().json;

const pickId = (value) => {
  if (value == null || value === '') return null;
  const num = Number(value);
  return Number.isFinite(num) && num > 0 ? num : null;
};
const pickBool = (value) => value === true || value === 'true';

const candidates = [];

if (Array.isArray(raw)) {
  candidates.push(...raw);
}

if (raw && typeof raw === 'object') {
  candidates.push(raw);

  for (const key of ['body', 'data', 'result']) {
    const nested = raw[key];
    if (Array.isArray(nested)) {
      candidates.push(...nested);
    } else if (nested && typeof nested === 'object') {
      candidates.push(nested);
    }
  }
}

let savedMessageId = null;
let savedMessageDuplicate = false;

for (const candidate of candidates) {
  if (!candidate || typeof candidate !== 'object') continue;
  savedMessageId = pickId(candidate.id ?? candidate.message_id ?? candidate.saved_message_id);
  savedMessageDuplicate = pickBool(candidate.duplicate);
  if (savedMessageId != null) break;
}

return [{
  json: {
    ...base,
    saved_message_id: savedMessageId,
    saved_message_duplicate: savedMessageDuplicate,
  }
}];

const item = $input.first().json;
await new Promise((resolve) => setTimeout(resolve, 8000));
return [{ json: item }];

const base = $('Wait 8s Debounce').first().json || {};
const rpcResult = $input.first().json;

const pickBool = (value) => value === true || value === 'true';
const pickId = (value) => {
  if (value == null || value === '') return null;
  const num = Number(value);
  return Number.isFinite(num) && num > 0 ? num : null;
};

const candidates = [];
const visit = (value) => {
  if (value == null) return;

  if (typeof value === 'string') {
    try {
      visit(JSON.parse(value));
    } catch (error) {}
    return;
  }

  if (typeof value === 'boolean') {
    candidates.push(value);
    return;
  }

  if (Array.isArray(value)) {
    for (const item of value) {
      visit(item);
    }
    return;
  }

  if (typeof value === 'object') {
    candidates.push(value);
    for (const key of ['body', 'data', 'result']) {
      visit(value[key]);
    }
  }
};

visit(rpcResult);

let isLatest = null;
let latestMessageId = null;
let checkedMessageId = pickId(base.saved_message_id);

for (const candidate of candidates) {
  if (typeof candidate === 'boolean') {
    isLatest = candidate;
    break;
  }

  if (!candidate || typeof candidate !== 'object') continue;

  if (latestMessageId == null) {
    latestMessageId = pickId(candidate.latest_message_id ?? candidate.latestMessageId);
  }

  if (checkedMessageId == null) {
    checkedMessageId = pickId(candidate.checked_message_id ?? candidate.checkedMessageId ?? candidate.message_id);
  }

  if (candidate.check_is_latest_message !== undefined) {
    isLatest = pickBool(candidate.check_is_latest_message);
    break;
  }

  if (candidate.result !== undefined && typeof candidate.result !== 'object') {
    isLatest = pickBool(candidate.result);
    break;
  }
}

if (isLatest == null && latestMessageId != null && checkedMessageId != null) {
  isLatest = latestMessageId === checkedMessageId;
}

const isDuplicateSavedMessage = base.saved_message_duplicate === true;
const debounceReason =
  base.saved_message_id == null
    ? 'missing_saved_message_id'
    : isDuplicateSavedMessage
      ? 'duplicate_saved_message'
      : base.is_empty
        ? 'empty_message'
        : isLatest == null
          ? 'rpc_shape_unknown'
          : isLatest === true
            ? 'latest'
            : 'not_latest';

return [{
  json: {
    ...base,
    should_continue: base.saved_message_id != null && isLatest === true && !base.is_empty && !isDuplicateSavedMessage,
    debounce_reason: debounceReason,
    rpc_is_latest: isLatest,
    rpc_latest_message_id: latestMessageId,
    rpc_checked_message_id: checkedMessageId,
  }
}];

const base = $('Debounce Check').first().json || {};
const raw = $input.first().json || {};
const context = raw.v20_build_turn_context || raw || {};
if (!context.store || typeof context.store !== 'object') {
  context.store = {};
}
return [{
  json: {
    ...base,
    context,
  }
}];

const row = $input.first().json || {};
const ctx = row.context || {};
const store = ctx.store || {};
const storeBits = [
  store.name ? `Nombre: ${store.name}` : '',
  store.store_address || store.address ? `Dirección: ${store.store_address || store.address}` : '',
  store.store_phone || store.phone ? `Tel: ${store.store_phone || store.phone}` : '',
  store.store_hours || store.hours ? `Horarios: ${store.store_hours || store.hours}` : '',
  store.store_website_url ? `Web: ${store.store_website_url}` : '',
].filter(Boolean);
const storeBlock = storeBits.length ? storeBits.join('\n') : '(Sin datos de tienda en API; pedí que un humano confirme horarios y dirección.)';
const recent = Array.isArray(ctx.recent_messages) ? ctx.recent_messages.slice(-8) : [];
const history = recent
  .map((m) => {
    const role = m.role === 'bot' ? 'Asistente' : 'Cliente';
    let txt = String(m.message || '').trim();
    if (!txt) return '';
    if (txt.length > 900) txt = txt.slice(0, 700) + '…';
    return `${role}: ${txt}`;
  })
  .filter(Boolean)
  .join('\n');
const firstName = String(row.first_name || 'ahí').trim() || 'ahí';
const priceBlock = String(ctx.pricelist_markdown || '').trim() || '(Lista de precios no disponible en el servidor; pedí que un humano confirme valores.)';
const agent_system_message = [
  'Sos el asistente virtual de TechnoStore en WhatsApp (celulares, accesorios, tecnología).',
  '',
  '## Estilo',
  '- Español rioplatense, natural, breve; como alguien del equipo.',
  '- Podés usar *negritas* y emojis como en WhatsApp cuando ayude a leer precios.',
  '',
  '## Hechos del local',
  '- Dirección, teléfono y horarios: SOLO del bloque TIENDA abajo.',
  '',
  '## Precios y financiación',
  '- Contado, reserva, cuotas y MACRO: usá ÚNICAMENTE el bloque LISTA DE PRECIOS; no inventes modelos ni cifras.',
  '- Si el cliente pide algo que no está en la lista, decí que un asesor confirma disponibilidad y precio.',
  '- Podés comentar características generales de equipos; montos siempre según la lista.',
  '',
  '## Contexto',
  '- No digas que buscaste en internet en tiempo real.',
  '- Off-topic: corto y redirigí a la tienda o celulares.',
  '',
  `## Cliente\nNombre de referencia: ${firstName}.`,
  '',
  '## TIENDA',
  storeBlock,
  '',
  '## LISTA DE PRECIOS (abril / archivo del servidor)',
  priceBlock,
].join('\n');
const userLine = String(row.user_message || '').trim().slice(0, 2000) || '(sin texto)';
const agent_user_prompt = [
  history ? `## Historial reciente\n${history}` : '',
  `## Mensaje actual\n${userLine}`,
].filter(Boolean).join('\n\n');
return [{ json: { ...row, agent_system_message, agent_user_prompt, groq_model: "qwen/qwen3-32b" } }];

const raw = $input.first().json || {};
const row = $('Build Groq Chat Request').first().json || {};
const ctx = row.context || {};
const text = String(
  raw.output ??
    raw.text ??
    (raw.json && typeof raw.json === 'object' ? raw.json.output : '') ??
    raw.choices?.[0]?.message?.content ??
    '',
).trim() || 'Perdón, ahora no pude responder. ¿Podés repetir en una frase qué necesitás?';
const chunkManyChat = (t, limit) => {
  const s = String(t || '').trim();
  if (!s) return [];
  const out = [];
  let rest = s;
  while (rest.length > limit) {
    let cut = rest.lastIndexOf('\n\n', limit);
    if (cut < limit * 0.4) cut = rest.lastIndexOf('. ', limit);
    if (cut < limit * 0.4) cut = limit;
    out.push(rest.slice(0, cut).trim());
    rest = rest.slice(cut).trim();
  }
  if (rest) out.push(rest);
  return out;
};
const parts = chunkManyChat(text, 1800);
const wa_messages = parts.map((p) => ({ type: 'text', text: p }));
const botMessageText = wa_messages.map((m) => m.text).join('\n\n────────\n\n');
const model = String(raw.model || row.groq_model || 'qwen/qwen3-32b').trim();
const router_output = {
  route_key: 'v20_groq_chat',
  confidence: 1,
  matched_product_keys: [],
  matched_brand: null,
  detected_city: null,
  detected_budget_range: null,
  detected_payment_method: null,
  rationale: 'v20 AI Agent (Groq)',
};
const responder_output = {
  selected_product_keys: [],
  actions: [],
  state_delta: { intent_key: 'v20_chat', funnel_stage: 'engaged', lead_score_delta: 1 },
  reply_text: botMessageText,
  raw_text: botMessageText,
};
const validator_output = {
  approved: true,
  reply_messages: wa_messages,
  selected_product_keys: [],
  actions: [],
  final_state_delta: {
    intent_key: 'v20_chat',
    funnel_stage: 'engaged',
    lead_score_delta: 1,
    selected_product_keys: [],
    share_store_location: false,
    tags_to_add: [],
    tags_to_remove: [],
    summary: 'Chat v20',
  },
  validation_errors: [],
  validation_warnings: [],
  fallback_reason: null,
};
return [{
  json: {
    ...row,
    context: ctx,
    router_output,
    responder_output,
    validator_output,
    should_send: true,
    bot_message_text: botMessageText,
    wa_messages,
    responder_provider_name: 'groq',
    responder_model_name: model,
  },
}];

const data = $('Build Groq Assistant Reply').first().json || $input.first()?.json || {};
const messages = Array.isArray(data.wa_messages)
  ? data.wa_messages
  : [{ type: 'text', text: data.bot_message_text || '' }];
const wa = [];
for (const m of messages) {
  if (m.type === 'image' && (m.image_url || m.url)) {
    const url = m.image_url || m.url;
    wa.push({ type: 'image', url, image_url: url });
    continue;
  }
  const t = String(m.text || '').trim();
  if (t) wa.push({ type: 'text', text: t });
}
return [{
  json: {
    ...data,
    payload: {
      subscriber_id: data.subscriber_id,
      data: {
        version: 'v2',
        content: {
          type: 'whatsapp',
          messages: wa,
        },
      },
    },
  }
}];

const data = $('Prepare WhatsApp Payload').first().json || {};
const sendResponse = $input.first().json || {};
return [{
  json: {
    ...data,
    send_result: {
      attempted: true,
      response: sendResponse,
      sent_at: new Date().toISOString(),
    },
  }
}];

const data = $('Build Groq Assistant Reply').first().json || $input.first()?.json || {};
return [{
  json: {
    ...data,
    should_send: false,
    send_result: {
      attempted: false,
      skipped: true,
      reason: 'reply_send_not_claimed',
      sent_at: new Date().toISOString(),
    },
  }
}];

const data = $input.first().json || {};
const parseJsonish = (value) => {
  if (typeof value !== 'string') return value;
  const trimmed = value.trim();
  if (!trimmed) return null;
  try {
    return JSON.parse(trimmed);
  } catch (error) {
    return value;
  }
};
const asRecord = (value) => {
  const parsed = parseJsonish(value);
  return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {};
};
const asArray = (value) => {
  const parsed = parseJsonish(value);
  return Array.isArray(parsed) ? parsed : [];
};
const toBool = (value) => {
  if (typeof value === 'boolean') return value;
  const normalized = String(value ?? '').trim().toLowerCase();
  return ['true', '1', 'yes', 'si', 'sí', 'y'].includes(normalized);
};
const extractReplyText = (messages) =>
  asArray(messages)
    .map((message) => {
      if (!message || typeof message !== 'object') return '';
      return String(message.text ?? message.reply_text ?? '').trim();
    })
    .filter(Boolean)
    .join('\n\n')
    .trim();

const context = asRecord(data.context);
const router = asRecord(data.router_output);
const responder = asRecord(data.responder_output);
const validator = asRecord(data.validator_output);
const state = asRecord(validator.final_state_delta);

const now = new Date().toISOString();
const currentTags = Array.isArray(context.customer?.tags) ? context.customer.tags : [];
const unique = (values) => [...new Set(values.filter(Boolean))];
const mergedTags = unique([
  ...currentTags,
  ...(Array.isArray(state.tags_to_add) ? state.tags_to_add : []),
]).filter((tag) => !(Array.isArray(state.tags_to_remove) ? state.tags_to_remove : []).includes(tag));

const currentLeadScore = Number(context.customer?.lead_score || 0);
const nextLeadScore = Math.max(0, Math.min(100, currentLeadScore + Number(state.lead_score_delta || 0)));
const selectedProductKeys = Array.isArray(validator.selected_product_keys) ? validator.selected_product_keys : [];

const updates = {
  last_bot_interaction: now,
  updated_at: now,
  last_intent: state.intent_key || null,
  funnel_stage: state.funnel_stage || null,
  lead_score: nextLeadScore,
  tags: mergedTags,
};

if (selectedProductKeys[0]) {
  updates.interested_product = selectedProductKeys[0];
}

if (state.payment_method_key) {
  updates.payment_method_last = state.payment_method_key;
}

const brandList = unique(selectedProductKeys
  .map((key) => {
    const product = (Array.isArray(context.candidate_products) ? context.candidate_products : []).find((item) => item.product_key === key);
    return product?.brand_key || null;
  })
  .filter(Boolean));

if (brandList.length > 0) {
  const currentBrands = Array.isArray(context.customer?.brands_mentioned) ? context.customer.brands_mentioned : [];
  updates.brands_mentioned = unique([...brandList, ...currentBrands]).slice(0, 10);
}

const conversationSummary = String(state.summary || router.rationale || 'Turno procesado').slice(0, 220);
const conversationInsights = unique([
  'Ruta ' + String(router.route_key || 'unknown'),
  ...selectedProductKeys.slice(0, 3).map((key) => 'Producto ' + key),
]).slice(0, 8);

const shouldPersistBotMessage = toBool(data.should_send);
const sendResult = asRecord(data.send_result);
const botMessageText = String(
  data.bot_message_text ||
    extractReplyText(data.wa_messages) ||
    extractReplyText(validator.reply_messages) ||
    responder.reply_text ||
    ''
).trim();

const botMessageRow = shouldPersistBotMessage
  ? {
      manychat_id: data.subscriber_id,
      customer_id: context.customer?.customer_id || null,
      role: 'bot',
      message: botMessageText,
      message_type: 'text',
      intent_detected: state.intent_key || null,
      products_mentioned: selectedProductKeys,
      triggered_human: false,
      was_audio: false,
      channel: 'manychat',
      external_message_id: null,
      whatsapp_phone_number_id: null,
      applied_tags: Array.isArray(state.tags_to_add) ? state.tags_to_add : [],
      payment_methods_detected: state.payment_method_key ? [state.payment_method_key] : [],
      brands_detected: brandList,
      topics_detected: [String(router.route_key || 'generic_sales')],
      funnel_stage_after: state.funnel_stage || null,
      conversation_summary: conversationSummary,
      conversation_insights: conversationInsights,
      lead_score_after: nextLeadScore,
      workflow_version: 'v20',
      route_key: router.route_key || 'generic_sales',
      send_result: sendResult,
    }
  : {
      skip_save: true,
      reason: 'reply_not_sent',
      manychat_id: data.subscriber_id,
      workflow_version: 'v20',
    };

return [{
  json: {
    ...data,
    customer_updates: updates,
    bot_message_row: botMessageRow,
}
}];

const base = $('Build Update Payload').first().json || {};

return [{
  json: {
    ...base,
    state_update_status: 'ok',
  }
}];
